  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  org_id INTEGER NULL,
  device_id TEXT NULL,
  trace_id TEXT NULL,
  span_id TEXT NULL,
  provider TEXT NULL,
  model TEXT NULL,
  tool_name TEXT NULL,
  input_tokens INTEGER NULL DEFAULT 0,
  output_tokens INTEGER NULL DEFAULT 0,
  latency_ms INTEGER NULL DEFAULT 0,
  cost_usd REAL NULL DEFAULT 0,
  status_code INTEGER NULL DEFAULT 200,
  is_approved INTEGER NULL DEFAULT 0,
  metadata TEXT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TRIGGER IF NOT EXISTS telemetry_events_updated_at
AFTER UPDATE ON telemetry_events
BEGIN
  UPDATE telemetry_events SET updated_at = datetime('now') WHERE id = NEW.id;
END;

-- Aggregated daily usage stats per org/device/provider
CREATE TABLE IF NOT EXISTS usage_dailys (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  org_id INTEGER NULL,
  device_id TEXT NULL,
  provider TEXT NULL,
  model TEXT NULL,
  date TEXT NULL,
  request_count INTEGER NULL DEFAULT 0,
  total_input_tokens INTEGER NULL DEFAULT 0,
  total_output_tokens INTEGER NULL DEFAULT 0,
  total_cost_usd REAL NULL DEFAULT 0,
  total_latency_ms INTEGER NULL DEFAULT 0,
  shadow_count INTEGER NULL DEFAULT 0,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TRIGGER IF NOT EXISTS usage_dailys_updated_at
AFTER UPDATE ON usage_dailys
BEGIN
  UPDATE usage_dailys SET updated_at = datetime('now') WHERE id = NEW.id;
END;

CREATE TABLE IF NOT EXISTS users (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  account_id INTEGER NULL,
  email TEXT NULL,
  name TEXT NULL,
  avatar_url TEXT NULL,
  role TEXT NULL DEFAULT 'user' CHECK(role IN ('owner', 'admin', 'user', 'viewer')),
  department TEXT NULL,
  job_title TEXT NULL,
  sso_id TEXT NULL,
  status TEXT NULL DEFAULT 'invited' CHECK(status IN ('active', 'invited', 'disabled', 'suspended')),
  last_login_at TEXT NULL,
  onboarding_complete INTEGER NULL DEFAULT 0,
  flusk_key TEXT NULL UNIQUE,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TRIGGER IF NOT EXISTS users_updated_at
AFTER UPDATE ON users
BEGIN
  UPDATE users SET updated_at = datetime('now') WHERE id = NEW.id;
END;

CREATE TABLE IF NOT EXISTS webhook_configs (
  id TEXT PRIMARY KEY DEFAULT (lower(hex(randomblob(16)))),
  bot_id TEXT NULL UNIQUE,
  verify_token TEXT NULL,
  api_secret TEXT NULL,
  provider TEXT NULL DEFAULT 'waha' CHECK(provider IN ('waha', 'twilio', 'meta-cloud')),
  webhook_url TEXT NULL,
  created_at TEXT NOT NULL DEFAULT (datetime('now')),
  updated_at TEXT NOT NULL DEFAULT (datetime('now'))
);

CREATE TRIGGER IF NOT EXISTS webhook_configs_updated_at
AFTER UPDATE ON webhook_configs
BEGIN
  UPDATE webhook_configs SET updated_at = datetime('now') WHERE id = NEW.id;
END;
